(8, '字段值替换', 3, 0, '将不符合预设规则的数据值替换为指定的默认值或空值。', 'A01A01A02', '0', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:35:19.0', '吴同', 1, TIMESTAMP '2025-08-11 11:41:37.0', NULL),
(9, '字符串转数值', 4, 0, '将纯数字字符串转换为数值类型', 'A01A02A01', '0', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:35:58.0', '吴同', 1, TIMESTAMP '2025-08-11 11:41:29.0', NULL),
(10, '字符串转日期', 4, 0, '规则描述：将符合格式的字符串转换为日期类型\n示例案例：“2025-07-01” → 日期类型', 'A01A02A02', '0', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:41:57.0', '吴同', 1, TIMESTAMP '2025-08-11 11:41:57.0', NULL),
(11, '任意类型转布尔值', 4, 0, '规则描述：将“是/否”、“1/0”、“true/false”等转换为布尔值\n示例案例：“是” → true', 'A01A02A03', '0', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:42:12.0', '吴同', 1, TIMESTAMP '2025-08-11 11:42:12.0', NULL),
(12, '手机号格式统一', 5, 0, '规则描述：统一手机号为国内11位纯数字格式，去除国家码、空格、短横线等\n示例案例：“+86-138 1234 5678” → “13812345678”', 'A01A03A01', '0', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:42:26.0', '吴同', 1, TIMESTAMP '2025-08-11 11:42:26.0', NULL),
(13, '日期格式统一', 5, 0, '规则描述：统一各种日期格式为指定标准格式（如 yyyy-MM-dd），支持配置模板\n示例案例：“20250701” → “2025-07-01”', 'A01A03A02', '0', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:43:47.0', '吴同', 1, TIMESTAMP '2025-08-11 11:43:47.0', NULL),
(14, '小数位统一', 5, 0, '规则描述：将数值字段统一保留指定的小数位数（如保留两位小数）\n示例案例：“12.3” → “12.30”；“100” → “100.00”', 'A01A03A03', '1', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:43:58.0', '吴同', 1, TIMESTAMP '2025-08-11 11:43:58.0', NULL),
(15, '去除字段空格', 5, 0, '规则描述：去除字段中的前后空格或中间多余空格，提升匹配准确性\n示例案例：“  山西 省  ” → “山西省”，收尾、中间等。', 'A01A03A04', '1', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:44:10.0', '吴同', 1, TIMESTAMP '2025-08-11 11:44:10.0', NULL),
(16, '字段前缀/后缀统一', 5, 0, '规则描述：对字段值统一加前缀或后缀，或去除非业务所需的标记\n示例案例：“编号123” → 去除“编号” → “123”', 'A01A03A05', '1', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:44:22.0', '吴同', 1, TIMESTAMP '2025-08-11 11:44:22.0', NULL),
(17, '正则表达式替换', 5, 0, NULL, 'A01A03A06', '1', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:44:31.0', '吴同', 1, TIMESTAMP '2025-08-11 11:44:31.0', NULL),
(18, '超长字段截断', 6, 0, '规则描述：当字段长度超过指定长度时进行截断处理\n示例案例：描述字段超100字符 → 截取前100字符', 'A01A04A01', '0', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:44:49.0', '吴同', 1, TIMESTAMP '2025-08-11 11:44:49.0', NULL),
(19, '字段补零', 6, 0, '规则描述：在字段前/后补0，保持固定长度\n示例案例：组织编码“1” → 补全为“00001”', 'A01A04A02', '0', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:44:59.0', '吴同', 1, TIMESTAMP '2025-08-11 11:44:59.0', NULL),
(20, '完整性修复', 0, 1, NULL, 'A02', '1', '0', '吴同', 1, TIMESTAMP '2025-08-11 11:45:11.0', '吴同', 1, TIMESTAMP '2025-08-11 11:45:31.0', NULL),
(21, '空值填充类', 20, 0, NULL, 'A02A01', '1', '0', '吴同', 1, TIMESTAMP '2025-08-11 11:45:27.0', '吴同', 1, TIMESTAMP '2025-08-11 11:46:00.0', NULL),
(22, '整行空记录删除类', 20, 1, NULL, 'A02A02', '1', '0', '吴同', 1, TIMESTAMP '2025-08-11 11:45:38.0', '吴同', 1, TIMESTAMP '2025-08-11 11:45:38.0', NULL),
(23, '数值空值填充', 21, 0, '规则描述：将空的数值字段填充为指定默认值（如 0、-1、平均数等）\n示例案例：年龄字段为空 → 配置默认值为 0', 'A02A01A01', '0', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:46:14.0', '吴同', 1, TIMESTAMP '2025-08-11 11:46:14.0', NULL),
(24, '字符串空值填充', 21, 1, '规则描述：将空的字符串字段填充为指定字符（如“未知”、“无”）\n示例案例：籍贯字段为空 → 配置默认值为“未知”', 'A02A01A02', '0', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:46:25.0', '吴同', 1, TIMESTAMP '2025-08-11 11:46:25.0', NULL),
(25, '布尔空值填充', 21, 2, '规则描述：布尔字段为空时填充为指定布尔值（如 false / true）\n示例案例：是否启用字段为空 → 配置默认值为 false', 'A02A01A03', '0', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:46:36.0', '吴同', 1, TIMESTAMP '2025-08-11 11:46:36.0', NULL),
(26, '日期空值填充', 21, 3, '规则描述：日期字段为空时填充为配置的默认日期（如当前日期、昨天、固定值等）\n示例案例：注册时间为空 → 配置默认值为“当前日期”', 'A02A01A04', '0', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:46:48.0', '吴同', 1, TIMESTAMP '2025-08-11 11:46:48.0', NULL),
(27, '全字段为空删除', 22, 0, '规则描述：整行所有字段都为空、null 或空字符串时，直接删除该记录\n示例案例：{姓名: null, 手机: \"\", 地址: null} → 删除', 'A02A02A01', '0', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:46:58.0', '吴同', 1, TIMESTAMP '2025-08-11 11:46:58.0', NULL),
(28, '组合字段为空删除', 22, 1, '规则描述：配置关键字段（如主键）为空时，删除整行记录\n示例案例：用户ID为 null → 删除该记录', 'A02A02A02', '0', '1', '吴同', 1, TIMESTAMP '2025-08-11 11:47:08.0', '吴同', 1, TIMESTAMP '2025-08-11 11:47:08.0', NULL),
(29, '一致性修正', 0, 2, NULL, 'A03', '1', '0', '吴同', 1, TIMESTAMP '2025-08-11 11:47:20.0', '吴同', 1, TIMESTAMP '2025-08-11 11:47:24.0', NULL),
(30, '单位标准化类', 29, 0, NULL, 'A03A01', '1', '0', '吴同', 1, TIMESTAMP '2025-08-11 11:47:34.0', '吴同', 1, TIMESTAMP '2025-08-11 11:47:34.0', NULL),
