(24, '枚举值映射标准化', '1', '将字段值根据配置字典进行映射替换，确保值域统一', '1', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:49:19.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:21:12.0', NULL, '“1” → “启用”；“0” → “停用”', '32', '将字段值根据配置字典进行映射替换，确保值域统一', 'MENU_CUSTOM', '024', 'A03A03'),
(25, '按主键去重（保留首条）', '1', '按指定唯一标识字段对记录去重，仅保留首条出现的数据，适用于无时间戳场景', '0', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:49:41.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:13:18.0', NULL, '按“客户ID”去重，保留最先出现的记录', '39', '按指定唯一标识字段对记录去重，仅保留首条出现的数据，适用于无时间戳场景', 'PK_DEDUP_FIRST', '025', 'A04A01'),
(26, '按主键去重（按时间字段保留最新）', '1', '配置时间字段，在重复记录中仅保留时间最新的一条', '0', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:49:57.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:13:14.0', NULL, '按“订单编号”去重，保留“更新时间”最大的一条记录', '39', '配置时间字段，在重复记录中仅保留时间最新的一条', NULL, '026', 'A04A01'),
(27, '按优先级字段保留记录', '1', '当记录存在多个来源或等级标记时，按照优先级高的记录进行保留', '0', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:50:15.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:13:09.0', NULL, '“数据来源”为“系统录入”优先于“Excel导入”，如果多条都是“系统录入”则应用最新一条', '39', '当记录存在多个来源或等级标记时，按照优先级高的记录进行保留', NULL, '027', 'A04A01'),
(28, '按非空字段优先保留记录', '1', '当关键字段存在空值时，优先保留值完整的记录', '0', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:50:33.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:13:05.0', NULL, '两条重复记录中一条手机号为空 → 保留手机号不为空的那条', '39', '当关键字段存在空值时，优先保留值完整的记录', NULL, '028', 'A04A01'),
(29, '按组合字段去重（保留最新或首条）', '1', '指定多个字段作为联合唯一键，对重复记录进行去重，可配置保留策略（首条、最新）', '1', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:50:50.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:21:19.0', NULL, '按“用户ID + 年份”去重，保留“更新时间”最大的一条记录', '39', '指定多个字段作为联合唯一键，对重复记录进行去重，可配置保留策略（首条、最新）', 'KEEP_LATEST_OR_FIRST', '029', 'A04A01'),
(30, '替换无效数值', '1', '将不在合法范围内的数值字段替换为指定默认值（如负数、过大值、异常标识值）', '0', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:51:21.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:12:24.0', NULL, '年龄字段为 -1 或 999 → 替换为 null 或 0', '46', '将不在合法范围内的数值字段替换为指定默认值（如负数、过大值、异常标识值）', NULL, '030', 'A05A01'),
(31, '替换非法枚举值', '1', '当字段值不在指定值域集合中时，替换为默认值或空值', '0', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:51:37.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:12:10.0', NULL, '状态字段值为“异常值99” → 替换为“未知”', '46', '当字段值不在指定值域集合中时，替换为默认值或空值', NULL, '031', 'A05A01'),
(32, '替换无效时间格式', '1', '当字段值不符合日期时间标准格式时，替换为默认时间或空值', '0', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:51:54.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:12:05.0', NULL, '“32/13/2023” → 替换为 null 或“1970-01-01”', '46', '当字段值不符合日期时间标准格式时，替换为默认时间或空值', NULL, '032', 'A05A01'),
(33, '替换非法布尔值', '1', '将字段中不符合布尔定义的值替换为默认布尔值', '0', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:52:10.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:12:01.0', NULL, '“abc” → 替换为 false', '46', '将字段中不符合布尔定义的值替换为默认布尔值', NULL, '033', 'A05A01'),
(34, '关键词脱敏', '1', '将字段值中包含的敏感词进行掩码处理，支持配置脱敏字符', '0', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:52:32.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:11:57.0', NULL, '“这是一条涉黄内容” → “这是一条***内容”', '47', '将字段值中包含的敏感词进行掩码处理，支持配置脱敏字符', NULL, '034', 'A05A02'),
(35, '敏感词替换', '1', '将命中词表中的敏感词替换为指定文本（如“未知”、“违规内容”）', '0', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:52:48.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:11:53.0', NULL, '“暴恐言论” → 替换为“违规内容”', '47', '将命中词表中的敏感词替换为指定文本（如“未知”、“违规内容”）', NULL, '035', 'A05A02'),
(36, '修正未来时间值', '1', '当时间字段值晚于当前时间时，自动修正为当前时间或指定边界值', '0', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:53:11.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:11:48.0', NULL, '注册时间为“2099-12-31” → 替换为“当前系统时间”', '55', '当时间字段值晚于当前时间时，自动修正为当前时间或指定边界值', NULL, '036', 'A06A01'),
(37, '校正超前时间差值', '1', '当字段时间超过当前时间指定间隔（如7天）时，进行修正处理', '0', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:53:27.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:11:43.0', NULL, '预约时间为当前时间+15天 → 替换为“当前时间+7天”', '55', '当字段时间超过当前时间指定间隔（如7天）时，进行修正处理', NULL, '037', 'A06A01'),
(38, '填补空时间为当前时间', '1', '当时间字段为空时，填充为系统当前时间或默认时间', '0', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:53:44.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:11:38.0', NULL, '更新时间字段为 null → 替换为“2025-07-18 10:00:00”', '56', '当时间字段为空时，填充为系统当前时间或默认时间', NULL, '038', 'A06A02'),
(39, '清理过期记录', '1', '当记录中的时间字段早于当前时间指定阈值时（如30天），标记或删除', '1', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:54:01.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:22:24.0', NULL, '最后登录时间早于30天前 → 该用户记录设为“过期”', '57', '当记录中的时间字段早于当前时间指定阈值时（如30天），标记或删除', 'CHECK_EXPIRATION', '039', 'A06A03'),
(40, '修正历史时间边界', '1', '当字段值早于系统可接受最早时间时，替换为指定边界值', '0', '0', '千桐科技', 1, TIMESTAMP '2025-08-11 14:54:16.0', '千桐科技', 1, TIMESTAMP '2025-08-11 17:10:19.0', NULL, '创建时间为“1900-01-01” → 替换为“2000-01-01”', '57', '当字段值早于系统可接受最早时间时，替换为指定边界值', NULL, '040', 'A06A03');
INSERT INTO public.tax_client (id, name, type, secret, homepage_url, allow_url, sync_url, logo, description, public_flag, valid_flag, del_flag, create_by, creator_id, create_time, update_by, updater_id, update_time, remark) VALUES
(1, '省级水资源监控系统', '0', '366c29e472774d368876144123b19b2c', NULL, NULL, NULL, '/profile/2025/09/30/68db939de4b0cf461aafd3a3.png', '作为上级业务平台，数据中台向该系统主动推送加工后的取水量分析结果、计划执行率等数据，用于其监管展示与预警。', '1', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 15:25:51.0', '吴同', 2, TIMESTAMP '2025-09-30 16:23:58.0', NULL),
(2, '信用信息共享平台', '0', 'c1be35d1cb344f8ca79d23741d77be84', NULL, NULL, NULL, '/profile/2025/09/30/68db93a4e4b0cf461aafd3a4.png', '作为上级业务平台，数据中台向该平台主动推送超计划用水、无证取水等失信行为数据，支撑信用惩戒信息归集。', '1', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 15:26:05.0', '吴同', 2, TIMESTAMP '2025-09-30 16:24:05.0', NULL),
(3, '政务服务网', '0', 'abbaa60f2f4b491f82269ebc3c083b35', NULL, NULL, NULL, '/profile/2025/09/30/68db93a9e4b0cf461aafd3a5.png', '作为上级业务平台，数据中台向该系统推送用水计划审批结果、申报状态更新等数据，实现审批信息回流与状态同步。', '1', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 15:26:57.0', '吴同', 2, TIMESTAMP '2025-09-30 16:24:10.0', NULL),
(4, '水文测报系统', '0', 'acfccbfc8d8e406f9e74925bb51c08c1', NULL, NULL, NULL, '/profile/2025/09/30/68db93aee4b0cf461aafd3a6.png', '作为同级平台，需从中台同步基础水文监测数据，经中台统一接入、清洗、治理后提供标准化服务。', '1', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 15:27:13.0', '吴同', 2, TIMESTAMP '2025-09-30 16:24:15.0', NULL),
(5, '灌区信息化系统', '0', '53ef84d0d89a4a6c8c03412c2f769438', NULL, NULL, NULL, '/profile/2025/09/18/68cbb45de4b0649f2379b125.png', '作为同级平台，其运行数据需接入中台，由中台完成数据汇聚、清洗与整合治理，形成农业用水统一视图。', '1', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 15:27:27.0', '吴同', 2, TIMESTAMP '2025-09-18 15:27:27.0', NULL),
(6, '电子证照系统', '0', '45ab41bbc4d24835995eac4d9417ae19', NULL, NULL, NULL, '/profile/2025/09/18/68cbb468e4b0649f2379b126.png', '作为同级平台，中台从中拉取证照信息后进行标准化处理与关联治理，用于用户身份核验与材料免提交支撑。', '1', '1', '1', '吴同', 2, TIMESTAMP '2025-09-18 15:27:38.0', '吴同', 2, TIMESTAMP '2025-09-18 15:27:38.0', NULL),
(7, '某县水资源管理系统', '0', '048823249e6747a0bb6a7db92627a360', NULL, NULL, NULL, '/profile/2025/09/18/68cbb475e4b0649f2379b127.png', '作为下级业务系统，需向数据中台定时上报取水许可、用水计划执行、重点取水户监测等数据，由中台统一汇聚、清洗与标准化治理，形成全域水资源管理数据视图。', '1', '1', '1', '吴同', 2, TIMESTAMP '2025-09-18 15:27:50.0', '吴同', 2, TIMESTAMP '2025-09-18 15:27:50.0', NULL),
(8, '某县防汛管理系统', '1', '83287261bb804d7bb39cb35b8b437730', NULL, NULL, NULL, '/profile/2025/09/18/68cbb481e4b0649f2379b128.png', '作为下级业务系统，需向数据中台实时/准实时同步汛情信息、险情处置、应急响应等数据，中台负责整合多源防汛数据，支撑市级及以上层面的统一监控与指挥调度。', '1', '1', '1', '吴同', 2, TIMESTAMP '2025-09-18 15:28:04.0', '吴同', 2, TIMESTAMP '2025-09-18 15:28:04.0', NULL),
(9, '某县灌区系统', '0', 'cb87541a26c44ecf84053c699720fb90', NULL, NULL, NULL, '/profile/2025/09/18/68cbb491e4b0649f2379b129.png', '作为下级信息化系统，需向数据中台报送渠首引水、灌溉轮次、田间用水等运行数据，由中台进行格式对齐、质量校验与融合分析，支撑农业用水总量核算与精细化管理。', '1', '1', '1', '吴同', 2, TIMESTAMP '2025-09-18 15:28:18.0', '吴同', 2, TIMESTAMP '2025-09-18 15:28:18.0', NULL);
