INSERT INTO public.tax_project (id, name, manager_id, description, valid_flag, del_flag, create_by, creator_id, create_time, update_by, updater_id, update_time, remark, code) VALUES
(1, '基础数据组', 2, '基础数据处理项目组，用于统一开展项目内各类基础数据的采集、治理与清洗工作，保障数据质量与一致性。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 14:50:43.0', '吴同', 2, TIMESTAMP '2025-09-22 19:21:32.0', NULL, '152317790975712'),
(2, '监测数据组', 2, '监测数据处理项目组，聚焦项目运行中的设备与系统监测数据（如传感器、日志、性能指标），负责本类数据的采集接入、清洗转换、模型构建与统一管理，支撑状态监控、异常预警及运维分析类数据服务。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 14:53:29.0', '吴同', 2, TIMESTAMP '2025-09-22 19:21:26.0', NULL, '152317955043040'),
(3, '业务数据组', 2, '业务数据处理项目组，围绕水利项目核心业务流程，负责水量调度、工程巡检、防汛工单、水文记录等结构化数据的汇聚整合、标准治理与加工处理，支撑业务统计、过程追溯与管理决策类数据应用。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 14:53:40.0', '吴同', 2, TIMESTAMP '2025-09-22 19:21:36.0', NULL, '152317966055136');
