(2, '水利数据质量类目', 0, 0, 'A01', '水利数据质量类目', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:09:46.0', '吴同', 2, TIMESTAMP '2025-09-18 16:10:21.0', NULL),
(3, '水资源管理', 2, 0, 'A01A01', '聚焦水资源的规划、配置与使用全过程数据，用于监控取用水、水量分配、用水效率等核心数据的完整性与合规性，支撑水资源总量与强度双控管理。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:09:55.0', '吴同', 2, TIMESTAMP '2025-09-18 16:09:55.0', NULL),
(4, '水雨情监测	', 2, 0, 'A01A02', '面向雨量、水位、流量等实时监测数据的质量管理，重点保障数据采集完整性、上报及时性和异常值控制，为防汛抗旱提供可靠数据支撑。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:10:58.0', '吴同', 2, TIMESTAMP '2025-09-18 16:10:58.0', NULL),
(5, '防洪减灾管理', 2, 0, 'A01A03', '管理洪水预警、风险点、灾情上报、应急响应等数据质量，确保关键信息完整、准确、可追溯，提升应急指挥决策的数据可信度。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:11:10.0', '吴同', 2, TIMESTAMP '2025-09-18 16:11:10.0', NULL),
(6, '水资源调度	', 2, 0, 'A01A04', '针对调度计划、指令执行、工程运行等调度过程数据的质量管控，保障调度数据的时效性、逻辑合理性和过程留痕完整性。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:11:17.0', '吴同', 2, TIMESTAMP '2025-09-18 16:11:17.0', NULL),
(7, '农村水利管理	', 2, 0, 'A01A05', '涵盖农村供水、灌区、小型水利设施等基础台账与运行数据，重点提升农村水利数据的覆盖度、更新及时性和服务人口匹配准确性。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:11:25.0', '吴同', 2, TIMESTAMP '2025-09-18 16:11:25.0', NULL),
(8, '河湖管理与保护', 2, 0, 'A01A06', '管理河湖名录、巡河记录、“四乱”问题、健康评价等数据，确保河湖监管数据的动态更新、空间一致性和问题闭环管理。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:11:32.0', '吴同', 2, TIMESTAMP '2025-09-18 16:11:32.0', NULL),
(9, '水文监测与情报', 2, 0, 'A01A07', '聚焦水文站网、整编资料、预报产品等专业水文数据，保障基础数据权威性、整编规范性和情报产品的发布及时性与准确性。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:11:42.0', '吴同', 2, TIMESTAMP '2025-09-18 16:11:42.0', NULL),
(10, '政务数据质量类目', 0, 1, 'A02', '政务数据质量类目', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:11:49.0', '吴同', 2, TIMESTAMP '2025-09-18 16:11:54.0', NULL),
(11, '政务服务', 10, 0, 'A02A01', '提供面向公众和企业的行政审批、办事服务与信息公开，提升政府服务效率与便民水平。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:12:01.0', '吴同', 2, TIMESTAMP '2025-09-18 16:12:01.0', NULL),
(12, '公共安全', 10, 0, 'A02A02', '防范和应对社会治安、安全生产、自然灾害等风险，保障人民生命财产安全和社会稳定。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:12:10.0', '吴同', 2, TIMESTAMP '2025-09-18 16:12:10.0', NULL),
(13, '城市治理', 10, 0, 'A02A03', '综合运用规划、管理与技术手段，提升城市运行效率、环境质量和公共服务水平。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:12:18.0', '吴同', 2, TIMESTAMP '2025-09-18 16:12:18.0', NULL),
(14, '农业数据质量类目', 0, 2, 'A03', '农业数据质量类目', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:12:26.0', '吴同', 2, TIMESTAMP '2025-09-18 16:12:26.0', NULL),
