(16, '农业科技', 14, 0, 'A03A02', '应用现代科技手段提升农业生产效率与可持续性，如智能农机、生物技术、数字农业等。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:12:43.0', '吴同', 2, TIMESTAMP '2025-09-18 16:12:43.0', NULL),
(17, '农村发展', 14, 0, 'A03A03', '推动乡村经济、基础设施、公共服务和生态环境整体提升，促进城乡协调发展。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:12:50.0', '吴同', 2, TIMESTAMP '2025-09-18 16:12:50.0', NULL),
(18, '制造业数据质量类目', 0, 3, 'A04', '制造业数据质量类目', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:12:59.0', '吴同', 2, TIMESTAMP '2025-09-18 16:12:59.0', NULL),
(19, '智能制造', 18, 0, 'A04A01', '融合自动化、信息化与人工智能技术，实现生产过程的智能化、柔性化与高效化。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:13:11.0', '吴同', 2, TIMESTAMP '2025-09-18 16:13:11.0', NULL),
(20, '产品研发', 18, 0, 'A04A02', '开展新产品设计、技术开发与测试验证，推动产品创新和企业核心竞争力提升。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:13:19.0', '吴同', 2, TIMESTAMP '2025-09-18 16:13:19.0', NULL),
(21, '供应链管理', 18, 0, 'A04A03', '对原材料采购、生产、物流、库存到销售的全过程进行计划、协调与优化管理。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 16:13:27.0', '吴同', 2, TIMESTAMP '2025-09-18 16:13:27.0', NULL);
