INSERT INTO public.tax_theme (id, name, icon, sort_order, description, valid_flag, del_flag, create_by, creator_id, create_time, update_by, updater_id, update_time, remark) VALUES
(1, '默认主题', NULL, 0, NULL, '1', '1', '吴大同', 1, TIMESTAMP '2025-09-16 17:34:31.0', '吴大同', 1, TIMESTAMP '2025-09-16 17:34:31.0', NULL),
(2, '水资源管理', NULL, 1, '聚焦区域水资源总量、水质状况、取用水行为等核心数据，涵盖地表水、地下水、非常规水源的监测与管理信息。通过统一归集与治理，支撑水资源承载能力评估、用水总量控制及可持续利用决策。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 15:18:15.0', '吴同', 2, TIMESTAMP '2025-09-18 15:18:22.0', NULL),
(3, '水雨情监测	', NULL, 2, '整合降水、水位、流量、流速等实时监测数据，覆盖雨量站、水文站、河道断面等感知节点。实现对流域内水情动态的全面掌握，为洪水预警、调度响应和应急指挥提供及时准确的数据支持。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 15:18:44.0', '吴同', 2, TIMESTAMP '2025-09-18 15:18:44.0', NULL),
(4, '防洪减灾管理', NULL, 3, '汇聚防洪预案、险情上报、应急响应、物资储备、转移安置等全过程管理数据，构建从风险识别到灾后评估的完整数据链条。支撑防汛指挥体系高效运转，提升灾害应对与风险防控能力。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 15:18:54.0', '吴同', 2, TIMESTAMP '2025-09-18 15:18:54.0', NULL),
(5, '水资源调度	', '/profile/2025/09/18/68cbb41fe4b0649f2379b121.png', 4, '管理跨区域、多水源的水量调度方案、调度指令、执行过程及效果反馈数据，涵盖水库、闸坝、泵站等关键工程调度行为。通过数据驱动优化配置流程，保障供水安全与生态需水。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 15:21:05.0', '吴同', 2, TIMESTAMP '2025-09-18 15:26:25.0', NULL),
(6, '农村水利管理	', '/profile/2025/09/18/68cbb42ae4b0649f2379b122.png', 5, '聚焦农村饮水安全、灌区运行、小型水利工程（如塘坝、机井）等管理数据，覆盖建设、运维、服务全生命周期。支撑农村水利精细化管理和乡村振兴战略实施。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 15:24:02.0', '吴同', 2, TIMESTAMP '2025-09-18 15:26:36.0', NULL),
(7, '河湖管理与保护', '/profile/2025/09/18/68cbb42fe4b0649f2379b123.png', 6, '整合河湖基础信息、水域岸线、排污口、涉水活动、河长巡河记录等数据，支撑河湖“四乱”治理、生态保护与长效监管。服务于河湖健康评价与生态文明建设。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 15:24:17.0', '吴同', 2, TIMESTAMP '2025-09-18 15:26:40.0', NULL),
(8, '水文监测与情报', '/profile/2025/09/18/68cbb433e4b0649f2379b124.png', 7, '负责水文要素的自动化采集、整编处理、质量控制与情报生成，包括水位、流量、泥沙、蒸发、水质等专业观测数据。作为水利基础数据底座，为各业务系统提供权威、可靠的水文信息服务。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-18 15:24:28.0', '吴同', 2, TIMESTAMP '2025-09-18 15:26:45.0', NULL);
INSERT INTO public.ast_asset (id, name, cat_code, datasource_id, table_name, table_comment, data_count, field_count, status, description, valid_flag, del_flag, create_by, creator_id, create_time, update_by, updater_id, update_time, remark, source, type, create_type, table_type, data_layer_id, business_category_id, business_category_code, data_domain_id, theme_domain_id, theme_domain_code, table_case, table_id) VALUES
(1, '水资源水位数据（原始库）', 'A03A02', 1, 'ods_wr_water_level', '水资源水位原始明细', 1000, 6, '2', '【Doris库、资产字段、资产预览、数据质量】外部系统采集的原始水位监测数据，字段保持源系统形态不做修改，主要用于数据质量溯源、原始备查。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-19 17:04:06.0', '吴同', 2, TIMESTAMP '2025-09-19 17:04:09.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(2, '水资源测站点数据（原始库）', 'A03A02', 1, 'ods_wr_water_level', '水资源水位原始明细', 1000, 6, '1', '【Doris库、资产字段、资产预览、数据质量】汇聚各外部系统（水资源管理、监测管理等）站点基础信息，字段原貌保存，支持跨源站点统一、后续维表加工。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-19 17:06:40.0', '吴同', 2, TIMESTAMP '2025-09-19 17:22:06.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(3, '水文监测流量数据（原始库）', 'A03A01', 1, 'ods_hyd_discharge', '水文监测流量时序数据', 1000, 11, '2', '【Doris库、资产字段、资产预览】接入水文监测平台的业务数据库，与第三方库数据保持一致，包含流量监测原始数据，用于水文计算、径流分析及防汛预警。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-19 17:08:24.0', '吴同', 2, TIMESTAMP '2025-09-19 17:22:08.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(4, '水文监测水位数据（原始库）', 'A03A01', 1, 'ods_hyd_water_level', '水文监测水位时序数据', 1000, 11, '2', '【Doris库、资产字段、资产预览、数据质量、数据血缘】接入水文监测平台的水位监测数据，包含站点实时及历史水位，用于水位变化分析和调度决策。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-19 17:09:19.0', '超级管理员', 1, TIMESTAMP '2025-09-22 16:23:33.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(5, '水文监测地理服务数据（原始库）', 'A03A02', -1, '-1', NULL, 0, 0, '2', '【外部API】接入水文监测相关的地理信息服务，提供河流、湖泊、取水口的空间位置数据，用于地图展示和空间分析。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-19 17:14:17.0', '吴同', 2, TIMESTAMP '2025-09-22 16:46:03.0', NULL, '3', '2', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(6, '水资源内部文件数据（原始库）', 'A03A02', 7, '-1', NULL, 0, 0, '2', '【FTP】存放水文监测管理系统的内部文档，如规划报告、批复文件、取水许可文档，用于文档归档与共享。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-19 17:16:25.0', '吴同', 2, TIMESTAMP '2025-09-19 17:17:20.0', NULL, '3', '7', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(7, '水位数据清洗结果表（明细库）', 'A04A03', 2, 'dwd_fact_water_level_clean', '清洗后的水位明细', 0, 9, '2', '【Doris库、资产字段、资产预览、数据血缘】在原始水位数据基础上完成 格式标准化、异常值处理、缺失值补全 等规则清洗，形成可信数据明细，供下游主题库使用。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-19 17:18:05.0', '吴同', 2, TIMESTAMP '2025-09-19 17:18:05.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(8, '水位数据去重表（明细库）', 'A04A03', 2, 'dwd_fact_water_level_dedup', '去重后的水位明细', 0, 6, '2', '【Doris库、资产字段、资产预览】按 station_code+obs_time 对清洗结果进行去重，保留最新或质量最优记录，解决多源或重复采集带来的冗余问题。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-19 17:18:55.0', '吴同', 2, TIMESTAMP '2025-09-22 15:56:13.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(9, '水位数据字段拆分表（明细库）', 'A04A03', 2, 'dwd_fact_water_level_split', '字段拆分后的水位明细', 0, 7, '2', NULL, '1', '1', '吴同', 2, TIMESTAMP '2025-09-19 17:19:26.0', '吴同', 2, TIMESTAMP '2025-09-19 17:19:26.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(10, '水位数据行转列表（明细库）', 'A04A03', 2, 'dwd_fact_water_level_unpivot', '行列转置中间层（可选）', 0, 6, '2', '【Doris库、资产字段、资产预览】将窄表形式的水位记录转为宽表指标存储（行转列），支持水位值、最大/最小值等多指标聚合，作为中间层结果或宽表存储', '1', '1', '吴同', 2, TIMESTAMP '2025-09-19 17:19:56.0', '吴同', 2, TIMESTAMP '2025-09-22 15:55:56.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(11, '水位预警分级表（主题库）', 'A05A01', 3, 'dws_water_level_warning_lvl', '水位预警分级', 0, 9, '2', '【Doris库、资产字段、资产预览、数据血缘】按照配置库阈值表 cfg_water_level_threshold 对清洗后的水位数据进行分级，输出红/黄/蓝/无预警等级，用于预警链路。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-19 17:20:14.0', '吴同', 2, TIMESTAMP '2025-09-19 17:20:14.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(12, '水位小时趋势表（主题库）', 'A05A01', 3, 'dws_water_level_daily_agg', '水位日级聚合', 0, 10, '2', '【Doris库、资产字段、资产预览、数据血缘】基于明细水位数据，按小时窗口计算均值、最大值、最小值、样本数，支持趋势分析与实时/批处理双模式写入。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-19 17:20:40.0', '吴同', 2, TIMESTAMP '2025-09-19 17:20:40.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(13, '水位小时实时看板（应用库）', 'A06A01', 4, 'ads_water_level_daily_report', '水位日统计报表', 0, 11, '2', '【Doris库、资产字段、资产预览、数据血缘】支撑大屏实时展示的小时均值指标表，逐分钟更新，体现最新水位监测动态。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-19 17:21:13.0', '吴同', 2, TIMESTAMP '2025-09-19 17:21:13.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(14, '水位日报表（应用库）', 'A06A01', 4, 'ads_water_level_hourly_realtime', '小时均值实时看板', 0, 4, '2', '【Doris库、资产字段、资产预览、数据血缘】按日统计水位均值、最大值、最小值、完整率、预警次数等指标，形成可直接展示的日报表，面向门户、报表系统和领导看板。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-19 17:21:45.0', '吴同', 2, TIMESTAMP '2025-09-19 17:21:45.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(15, '水资源测站点数据（原始库）', 'A03A02', 1, 'ods_wr_station', '水资源站点基础信息', 16000, 11, '2', '【Doris库、资产字段、资产预览】汇聚各外部系统（水资源管理、监测管理等）站点基础信息，字段原貌保存，支持跨源站点统一、后续维表加工。\n', '1', '1', '吴同', 2, TIMESTAMP '2025-09-19 17:33:56.0', '超级管理员', 1, TIMESTAMP '2025-09-22 16:23:41.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(16, '站点水位明细表（明细库）', 'A04A03', 2, 'dwd_water_level_clean_outlier', '站点水位明细表（异常值剔除）', 0, 6, '2', '【Doris库、资产字段、资产预览、数据血缘】Doris 明细库，用于存储站点水位原始明细的清洗结果，剔除异常值，水位值保留 2 位小数，支撑数据质量核查与后续统计分析。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-22 16:05:51.0', '超级管理员', 1, TIMESTAMP '2025-09-22 16:24:28.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(17, '站点水位明细表（明细库）', 'A04A03', 2, 'dwd_water_level_clean_missing', '站点水位明细表（缺失值补全）', 6013, 6, '2', '【Doris库、资产字段、资产预览、数据血缘】Doris 明细库，用于保存站点水位数据中缺失值补全后的清洗明细，保证数据完整性，支撑时序分析与月报生成。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-22 16:09:42.0', '超级管理员', 1, TIMESTAMP '2025-09-22 16:24:20.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(18, '站点水位明细表（明细库）', 'A04A03', 2, 'dwd_water_level_clean_std', '站点水位明细表（格式标准化，水位值保留2位小数）', 6000, 6, '2', '【Doris库、资产字段、资产预览、数据血缘】Doris 明细库，存放格式标准化后的水位明细表，统一字段精度与格式，保证跨库统计口径一致。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-22 16:10:09.0', '超级管理员', 1, TIMESTAMP '2025-09-22 16:24:22.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(19, '站点水位月报表（明细库）', 'A04A03', 2, 'dwd_station_water_month_report', '站点水位月报表', 180, 4, '2', '【Doris库、资产字段、资产预览、数据血缘】Doris 明细库，存放站点逐月平均水位数据，包含测站编码、名称及月均水位指标，支撑月度统计与调度。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-22 16:10:37.0', '超级管理员', 1, TIMESTAMP '2025-09-22 16:23:59.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(20, '站点水位月报宽表（明细库）', 'A04A03', 2, 'dwd_station_water_month_report_wide', '站点水位月报宽表（2025-01 至 2025-07）', 20, 9, '2', '【Doris库、资产字段、资产预览、数据血缘】Doris 明细库，以宽表形式保存逐月逐站点水位明细（2025-01, 2025-02…），方便报表展示和横向对比。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-22 16:11:45.0', '超级管理员', 1, TIMESTAMP '2025-09-22 16:23:57.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(21, '流域水位月报表（应用库）', 'A06A01', 4, 'ads_basin_water_month_report_wide_append', '流域水位月报表（追加写）', 45, 6, '2', '【Doris库、资产字段、资产预览、数据血缘】Doris 应用层，以追加方式存放流域月度水位汇总（宽表结构），支撑跨流域水资源对比与调度。', '1', '1', '吴同', 2, TIMESTAMP '2025-09-22 16:13:31.0', '超级管理员', 1, TIMESTAMP '2025-09-22 16:25:57.0', NULL, '3', '1', '2', '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
