INSERT INTO public.ast_sensitive_level (id, sensitive_level, sensitive_rule, start_char_loc, end_char_loc, mask_character, online_flag, description, valid_flag, del_flag, create_by, creator_id, create_time, update_by, updater_id, update_time, remark) VALUES
(1, '1级（绝密）', '1', NULL, NULL, '****', '1', '包含国家涉密信息、重大水利工程调度方案、涉安全生产的核心数据，一旦泄露将严重危害国家安全和重大工程运行安全。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-22 11:29:21.0', '吴同', 2, TIMESTAMP '2025-09-22 11:29:21.0', NULL),
(2, '2级（机密）', '1', NULL, NULL, '####', '1', '涉及水资源调度、水库运行、水源地保护、重要断面水质等关键业务数据，一旦泄露将影响行业管理和区域安全。', '1', '0', '吴同', 2, TIMESTAMP '2025-09-22 11:30:44.0', '吴同', 2, TIMESTAMP '2025-09-22 11:30:44.0', NULL),
(3, '3级（秘密）', '2', 2, 10, '****', '1', '涉及日常监测数据（如流量、水位、雨量等明细）、取水户用水记录、内部分析报表等，一旦泄露会对业务管理和内部运行造成不利影响。保留前3位，其余用***替代（如“孙燕姿”→“孙***”）', '1', '0', '吴同', 2, TIMESTAMP '2025-09-22 11:31:05.0', '吴同', 2, TIMESTAMP '2025-09-22 11:31:05.0', NULL),
(4, '4级（内部）', '2', 3, 8, '****', '1', '一般内部使用数据，如运维日志、调度流程记录、一般统计数据等，泄露影响较小但仍需内部保护。脱敏处理部分关键字段，如手机号138****5678', '1', '0', '吴同', 2, TIMESTAMP '2025-09-22 11:34:28.0', '吴同', 2, TIMESTAMP '2025-09-22 11:34:28.0', NULL),
(5, '5级（公开）', '1', NULL, NULL, '****', '1', '可以对外公开的数据，如水雨情简报、已公开的监测站点水质年报、宣传类信息等，不涉及安全和隐私。可直接展示或仅弱化部分敏感字段（如展示省、市，不展示精确坐标）', '1', '0', '吴同', 2, TIMESTAMP '2025-09-22 11:34:54.0', '吴同', 2, TIMESTAMP '2025-09-22 11:34:54.0', NULL);
