INSERT INTO public.mdl_data_layer (id, name, eng_name, owner_user_id, category, description, valid_flag, del_flag, create_by, creator_id, create_time, update_by, updater_id, update_time, remark) VALUES
(1, '操作数据层', 'ODS', 1, '1', '也叫贴源层,本层直接存放从业务系统抽取过来的数据,这些数据从结构上和数据上与业务系统保持一致,降低了数据抽取的复杂性。', '1', '0', '吴同', 2, TIMESTAMP '2026-03-25 09:46:09.722', '吴同', 2, TIMESTAMP '2026-03-25 09:46:09.722', NULL),
(2, '维度层', 'DIM', 1, '2', '以维度作为建模驱动，基于每个维度的业务含义，通过添加维度属性、关联维度等定义计算逻辑，完成属性定义的过程并建立一致的数据分析维表。为了避免在维度模型中冗余关联维度的属性，基于雪花模型构建维度表。', '1', '0', '吴同', 2, TIMESTAMP '2026-03-25 10:14:31.637', '吴同', 2, TIMESTAMP '2026-03-25 10:14:31.637', NULL),
(3, '明细数据层', 'DWD', 1, '2', '以业务过程作为建模驱动，基于每个具体的业务过程特点，构建最细粒度的明细事实表。可将某些重要属性字段做适当冗余，也即宽表化处理。', '1', '0', '吴同', 2, TIMESTAMP '2026-03-25 10:15:06.151', '吴同', 2, TIMESTAMP '2026-03-25 10:15:06.151', NULL),
(4, '汇总数据层', 'DWS', 1, '2', '以分析的主题对象作为建模驱动，基于上层的应用和产品的指标需求，构建公共粒度的汇总指标表。以宽表化手段物理化模型，构建命名规范、口径一致的统计指标，为上层提供公共指标，建立汇总宽表、明细事实表。', '1', '0', '吴同', 2, TIMESTAMP '2026-03-25 10:15:29.193', '吴同', 2, TIMESTAMP '2026-03-25 10:15:29.193', NULL),
(5, '数据应用层', 'ADS', 1, '3', '存放数据产品个性化的统计指标数据，报表数据。主要是提供给数据产品和数据分析使用的数据，通常根据业务需求，划分成流量、订单、用户等，生成字段比较多的宽表，用于提供后续的业务查询，OLAP分析，数据分发等。', '1', '0', '吴同', 2, TIMESTAMP '2026-03-25 10:15:52.556', '吴同', 2, TIMESTAMP '2026-03-25 10:15:52.556', NULL);
