INSERT INTO public.std_document (id, code, name, cat_code, type, status, issuing_agency, version, release_date, implementation_date, abolition_date, file_url, file_name, valid_flag, del_flag, create_by, creator_id, create_time, update_by, updater_id, update_time, remark, description) VALUES
(1, 'YLSL2023', '水利对象基础数据库表结构与标识符', 'A01A01', '3', '3', '伊犁哈萨克自治州水利局', NULL, NULL, NULL, NULL, '/profile/2025/09/19/68ccc254e4b0649f2379b12a.pdf', '68ccc254e4b0649f2379b12a.pdf', '1', '0', '吴同', 2, TIMESTAMP '2025-09-19 10:40:48.0', '吴同', 2, TIMESTAMP '2025-09-23 13:55:04.0', NULL, '用于规范水利对象基础信息数据库的表结构及标识符。'),
(2, 'SL202', '地表水、地下水取用水监测数据集成技术指南', 'A03A02', '3', '3', '新疆维吾尔自治区水资源中心', NULL, NULL, NULL, NULL, '/profile/2025/09/19/68ccc304e4b0649f2379b12b.doc', '68ccc304e4b0649f2379b12b.doc', '1', '0', '吴同', 2, TIMESTAMP '2025-09-19 10:43:49.0', '吴同', 2, TIMESTAMP '2025-09-23 13:55:12.0', NULL, '用于规范各地（州、市）一级取水口（地表水、地下水）监测数据的接入工作。'),
(3, 'YLSL 2023', '水雨情数据库表结构与标识符', 'A01A01', '3', '3', '伊犁州', NULL, NULL, NULL, NULL, '/profile/2025/09/19/68ccc39ee4b0649f2379b12c.docx', '68ccc39ee4b0649f2379b12c.docx', '1', '0', '吴同', 2, TIMESTAMP '2025-09-19 10:45:56.0', '吴同', 2, TIMESTAMP '2025-09-23 13:57:29.0', NULL, '水雨情数据库表结构与标识符'),
(4, 'SL/T 809-2021', '水利对象基础数据库表结构及标识符', 'A02A01', '1', '3', '水利部', NULL, NULL, NULL, NULL, '/profile/2025/09/19/68ccc3f1e4b0649f2379b12d.pdf', '68ccc3f1e4b0649f2379b12d.pdf', '1', '0', '吴同', 2, TIMESTAMP '2025-09-19 10:47:54.0', '吴同', 2, TIMESTAMP '2025-09-23 13:54:10.0', NULL, '本标准规定了水利对象类标识、水利对象名录表、水利对象基础信息表结构及标识符、水利对象关系表表结构规则和常用对象关系表清单。'),
(5, 'SL513—2011', '水土保持数据库表结构及标识符', 'A06A01', '1', '3', '水利部', NULL, NULL, NULL, NULL, '/profile/2025/09/19/68ccc54de4b0649f2379b12e.pdf', '68ccc54de4b0649f2379b12e.pdf', '1', '0', '吴同', 2, TIMESTAMP '2025-09-19 10:53:14.0', '吴同', 2, TIMESTAMP '2025-09-23 13:54:13.0', NULL, '本标准适用于全国各级水土保持部门和其他相关单位的水土保持数据库建设，以及与其相关的数据查询、信息发布和应用服务软件开发等'),
(6, '水信息219号', '水利业务需求分析报告', 'A06A01', '1', '3', NULL, NULL, NULL, NULL, NULL, '/profile/2025/09/19/68ccc6f4e4b0649f2379b130.pdf', '68ccc6f4e4b0649f2379b130.pdf', '1', '0', '吴同', 2, TIMESTAMP '2025-09-19 11:00:40.0', '吴同', 2, TIMESTAMP '2025-09-23 13:54:16.0', NULL, '概要说明水利十大业务需求分析的工作背景、目标内容、思路方法、工作过程，并简述了职能、现状、问题、目标、功能以及统筹信息化建设需求等主要分析成果'),
(7, 'SL323-2011', '实时雨水情数据库表结构与标识符', 'A01A01', '2', '3', NULL, NULL, NULL, NULL, NULL, '/profile/2025/09/19/68ccc796e4b0649f2379b131.pdf', '68ccc796e4b0649f2379b131.pdf', '1', '0', '吴同', 2, TIMESTAMP '2025-09-19 11:02:29.0', '吴同', 2, TIMESTAMP '2025-09-23 13:54:33.0', NULL, '水利行业实时雨水情数据库表结构与标识符的基本规定'),
(8, 'YLSL2023', '河长制湖长制管理信息系统建设技术指南', 'A04A01', '2', '3', NULL, NULL, NULL, NULL, NULL, '/profile/2025/09/19/68ccc8c9e4b0649f2379b133.pdf', '68ccc8c9e4b0649f2379b133.pdf', '1', '0', '吴同', 2, TIMESTAMP '2025-09-19 11:07:48.0', '吴同', 2, TIMESTAMP '2025-09-23 13:54:40.0', NULL, '适用于全国各级河长制湖长制管理信息系统的设计、建设和运行管理等。'),
(9, '新水办326号', '小水电生态监管数据接入通知', 'A04A04', '2', '3', NULL, NULL, NULL, NULL, NULL, '/profile/2025/09/19/68ccc943e4b0649f2379b134.pdf', '68ccc943e4b0649f2379b134.pdf', '1', '0', '吴同', 2, TIMESTAMP '2025-09-19 11:16:34.0', '吴同', 2, TIMESTAMP '2025-09-23 13:54:45.0', NULL, '小水电生态监管通知'),
(10, 'YLSL2023', '水雨情数据库表结构与标识符', 'A01A01', '2', '3', NULL, NULL, NULL, NULL, NULL, '/profile/2025/09/19/68cccb28e4b0649f2379b135.docx', '68cccb28e4b0649f2379b135.docx', '1', '0', '吴同', 2, TIMESTAMP '2025-09-19 11:18:06.0', '吴同', 2, TIMESTAMP '2025-09-23 13:54:50.0', NULL, '为统一实时雨水情数据库表结构和标识符'),
(11, 'YLSL2023', '数据共享使用办法', 'A04A04', '3', '3', NULL, NULL, NULL, NULL, NULL, '/profile/2025/09/19/68cccb93e4b0649f2379b137.docx', '68cccb93e4b0649f2379b137.docx', '1', '0', '吴同', 2, TIMESTAMP '2025-09-19 11:20:03.0', '吴同', 2, TIMESTAMP '2025-09-23 13:55:16.0', NULL, '为规范和促进伊犁州水利系统互联和水利数据共享，规范水利数据共享管理工作'),
(12, 'SL707', '水利政务信息数据库表结构', 'A06A02', '2', '3', NULL, NULL, NULL, NULL, NULL, '/profile/2025/09/19/68cccc23e4b0649f2379b139.pdf', '68cccc23e4b0649f2379b139.pdf', '1', '0', '吴同', 2, TIMESTAMP '2025-09-19 11:23:06.0', '吴同', 2, TIMESTAMP '2025-09-23 13:54:55.0', NULL, '本标准规定了水利政务各业务系统建设过程中的共享或交换信息的数据库表结构及标识符的表示方法、结构定义和编码原则。各水利政务应用的其他类信息的定义应遵循相关类别数据库表结构及标识符标准。'),
(13, 'YLSL 078', '数据维护更新办法', 'A04A01', '4', '3', NULL, NULL, NULL, NULL, NULL, '/profile/2025/09/19/68cccd12e4b0649f2379b13a.docx', '68cccd12e4b0649f2379b13a.docx', '1', '0', '吴同', 2, TIMESTAMP '2025-09-19 11:26:18.0', '吴同', 2, TIMESTAMP '2025-09-23 13:57:20.0', NULL, '加强水利数据资源服务的管理，规范整合数据资源的使用');
