INSERT INTO public.col_etl_sql_temp (id, name, type, content, description, valid_flag, del_flag, create_by, creator_id, create_time, update_by, updater_id, update_time, remark) VALUES
(1, 'create.table.kafka', '10', 'CREATE TABLE Kafka_Table (\n  event_time TIMESTAMP(3) METADATA FROM ''timestamp'',\n  partition BIGINT METADATA VIRTUAL,\n  offset BIGINT METADATA VIRTUAL,\n  user_id BIGINT,\n  item_id BIGINT,\n  behavior STRING\n) WITH (\n  ''connector'' = ''kafka'',\n  ''topic'' = ''user_behavior'',\n  ''properties.bootstrap.servers'' = ''localhost:9092'',\n  ''properties.group.id'' = ''testGroup'',\n  ''scan.startup.mode'' = ''earliest-offset'',\n  ''format'' = ''csv''\n);\n--可选: ''value.fields-include'' = ''ALL'',\n--可选: ''json.ignore-parse-errors'' = ''true'',\n--可选: ''key.fields-prefix'' = ''k_'',', 'kafka快速建表格式', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:19:31.0', NULL, NULL, TIMESTAMP '2025-06-25 14:19:31.0', NULL),
(2, 'create.table.doris', '10', 'CREATE TABLE doris_table (\n    cid INT,\n    sid INT,\n    name STRING,\n    cls STRING,\n    score INT,\n    PRIMARY KEY (cid) NOT ENFORCED\n) WITH (\n''connector'' = ''doris'',\n''fenodes'' = ''127.0.0.1:8030'' ,\n''table.identifier'' = ''test.scoreinfo'',\n''username'' = ''root'',\n''password''=''''\n);', 'Doris快速建表', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:19:31.0', NULL, NULL, TIMESTAMP '2025-06-25 14:19:31.0', NULL),
(3, 'create.table.jdbc', '10', 'CREATE TABLE JDBC_table (\n  id BIGINT,\n  name STRING,\n  age INT,\n  status BOOLEAN,\n  PRIMARY KEY (id) NOT ENFORCED\n) WITH (\n   ''connector'' = ''jdbc'',\n   ''url'' = ''jdbc:mysql://localhost:3306/mydatabase'',\n   ''table-name'' = ''users'',\n   ''username'' = ''root'',\n   ''password'' = ''123456''\n);\n--可选: ''sink.parallelism''=''1'',\n--可选: ''lookup.cache.ttl''=''1000s'',', 'JDBC建表语句', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:19:32.0', NULL, NULL, TIMESTAMP '2025-06-25 14:19:32.0', NULL),
(4, 'create.catalog.hive', '10', 'CREATE CATALOG hive WITH (\n    ''type'' = ''hive'',\n    ''default-database'' = ''default'',\n    ''hive-conf-dir'' = ''/app/wwwroot/MBDC/hive/conf/'', --hive配置文件\n    ''hadoop-conf-dir''=''/app/wwwroot/MBDC/hadoop/etc/hadoop/'' --hadoop配置文件，配了环境变量则不需要。\n);', '创建HIVE的catalog', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:19:32.0', NULL, NULL, TIMESTAMP '2025-06-25 14:19:32.0', NULL),
(6, 'use.catalog.hive', '10', 'USE CATALOG hive;', '使用hive的catalog', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:17.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:17.0', NULL),
(7, 'use.catalog.default', '10', 'USE CATALOG default_catalog;', '使用default的catalog', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:17.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:17.0', NULL),
(8, 'create.stream.table.hive', '10', 'CREATE CATALOG hive WITH ( --创建hive的catalog\n    ''type'' = ''hive'',\n    ''hive-conf-dir'' = ''/app/wwwroot/MBDC/hive/conf/'',\n    ''hadoop-conf-dir''=''/app/wwwroot/MBDC/hadoop/etc/hadoop/''\n);\nUSE CATALOG hive;\nUSE offline_db; --选择库\nset table.sql-dialect=hive; --设置方言\nCREATE TABLE hive_stream_table (\n  user_id STRING,\n  order_amount DOUBLE\n) PARTITIONED BY (dt STRING, hr STRING) STORED AS parquet TBLPROPERTIES (\n  ''partition.time-extractor.timestamp-pattern''=''$dt $hr:00:00'',\n  ''sink.partition-commit.trigger''=''partition-time'',\n  ''sink.partition-commit.delay''=''1min'',\n  ''sink.semantic'' = ''exactly-once'',\n  ''sink.rolling-policy.rollover-interval'' =''1min'',\n  ''sink.rolling-policy.check-interval''=''1min'',\n  ''sink.partition-commit.policy.kind''=''metastore,success-file''\n);', '创建流式HIVE表', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL),
(9, 'create.table.mysql_cdc', '10', 'CREATE TABLE mysql_cdc_table(\n    cid INT,\n    sid INT,\n    cls STRING,\n    score INT,\n    PRIMARY KEY (cid) NOT ENFORCED\n) WITH (\n''connector'' = ''mysql-cdc'',\n''hostname'' = ''127.0.0.1'',\n''port'' = ''3306'',\n''username'' = ''test'',\n''password'' = ''123456'',\n''database-name'' = ''test'',\n''server-time-zone'' = ''UTC'',\n''scan.incremental.snapshot.enabled'' = ''true'',\n''debezium.snapshot.mode''=''latest-offset'' ,-- 或者key是scan.startup.mode，initial表示要历史数据，latest-offset表示不要历史数据\n''debezium.timestamp(6).format.date''=''yyyy-MM-dd'',\n''debezium.timestamp(6).format.time''=''HH-mm-ss'',\n''debezium.timestamp(6).format.timestamp(6)''=''yyyy-MM-dd HH-mm-ss'',\n''debezium.timestamp(6).format.timestamp''=''yyyy-MM-dd HH-mm-ss'',\n''debezium.timestamp(6).format.timestamp.zone''=''UTC+8'',\n''table-name'' = ''mysql_cdc_table'');', '创建Mysql_CDC表', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL),
(10, 'create.table.hudi', '10', 'CREATE TABLE hudi_table\n(\n    goods_order_id  bigint COMMENT ''自增主键id'',\n    goods_order_uid string COMMENT ''订单uid'',\n    customer_uid    string COMMENT ''客户uid'',\n    customer_name   string COMMENT ''客户name'',\n    create_time     timestamp(3) COMMENT ''创建时间'',\n    update_time     timestamp(3) COMMENT ''更新时间'',\n    create_by       string COMMENT ''创建人uid（唯一标识）'',\n    update_by       string COMMENT ''更新人uid（唯一标识）'',\n    PRIMARY KEY (goods_order_id) NOT ENFORCED\n) COMMENT ''hudi_table''\nWITH (\n''connector'' = ''hudi'',\n''path'' = ''hdfs://cluster1/data/bizdata/cdc/mysql/order/goods_order'', -- 路径会自动创建\n''hoodie.datasource.write.recordkey.field'' = ''goods_order_id'', -- 主键\n''write.precombine.field'' = ''update_time'', -- 相同的键值时，取此字段最大值，默认ts字段\n''read.streaming.skip_compaction'' = ''true'', -- 避免重复消费问题\n''write.bucket_assign.tasks'' = ''2'', -- 并发写的 bucekt 数\n''write.tasks'' = ''2'',\n''compaction.tasks'' = ''1'',\n''write.operation'' = ''upsert'', -- UPSERT（插入更新）\\INSERT（...', '创建hudi表', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL),
(11, 'CREATE TABLE Like', '10', 'DROP TABLE IF EXISTS sink_table;\nCREATE TABLE IF not EXISTS sink_table\nWITH (\n    ''topic'' = ''motor_vehicle_error''\n)\nLIKE source_table;', 'CREATE TABLE Like source table', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL),
(12, 'CREATE TABLE like source_table EXCLUDING', '10', 'DROP TABLE IF EXISTS sink_table;\nCREATE TABLE IF not EXISTS sink_table(\n     -- Add watermark definition\n    WATERMARK FOR order_time AS order_time - INTERVAL ''5'' SECOND\n)\nWITH (\n    ''topic'' = ''motor_vehicle_error''\n)\nLIKE source_table (\n     -- Exclude everything besides the computed columns which we need to generate the watermark for.\n    -- We do not want to have the partitions or filesystem options as those do not apply to kafka.\n    EXCLUDING ALL\n    INCLUDING GENERATED\n);', 'CREATE TABLE like source_table EXCLUDING', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:54.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:54.0', NULL),
(13, 'CREATE TABLE ctas_kafka', '10', 'CREATE TABLE my_ctas_table\nWITH (\n    ''connector'' = ''kafka''\n)\nAS SELECT id, name, age FROM source_table WHERE mod(id, 10) = 0;', 'CREATE TABLE ctas_kafka', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:54.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:54.0', NULL),
(14, 'CREATE TABLE rtas_kafka', '10', 'CREATE OR REPLACE TABLE my_ctas_table\nWITH (\n    ''connector'' = ''kafka''\n)\nAS SELECT id, name, age FROM source_table WHERE mod(id, 10) = 0;', 'CREATE TABLE rtas_kafka', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:55.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:55.0', NULL),
(15, 'datagen job demo', '10', 'DROP TABLE IF EXISTS source_table3;\nCREATE TABLE IF NOT EXISTS source_table3(\n--订单id\norder_id BIGINT,\n--产品\nproduct BIGINT,\n--金额\namount BIGINT,\n--支付时间\norder_time as CAST(CURRENT_TIMESTAMP AS TIMESTAMP(3)), -- 在这里插入代码片\n--WATERMARK\nWATERMARK FOR order_time AS order_time - INTERVAL ''2'' SECOND\n) WITH(\n''connector'' = ''datagen'',\n ''rows-per-second'' = ''1'',\n ''fields.order_id.min'' = ''1'',\n ''fields.order_id.max'' = ''2'',\n ''fields.amount.min'' = ''1'',\n ''fields.amount.max'' = ''10'',\n ''fields.product.min'' = ''1'',\n ''fields.product.max'' = ''2''\n);\n-- SELECT * FROM source_table3 LIMIT 10;\nDROP TABLE IF EXISTS sink_table5;\nCREATE TABLE IF NOT EXISTS sink_table5(\n--产品\nproduct BIGINT,\n--金额\namount BIGINT,\n--支付时间\norder_time TIMESTAMP(3),\n--1分钟时间聚合总数\none_minute_sum BIGINT\n) WITH(\n''connector''=''print''\n);\nINSERT INTO sink_table5\nSELECT\nproduct,\namount,\norder_time,\nSUM(amount) OVER(\nPARTITION BY product\nORDER BY order_time\n-- 标识统计范围是1个 product...', 'datagen job demo', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:55.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:55.0', NULL),
(16, 'checkpoint config', '10', '-- 声明一些调优参数 (checkpoint 等相关配置)\nset ''execution.checkpointing.checkpoints-after-tasks-finish.enabled'' =''true'';\nSET ''pipeline.operator-chaining'' = ''false'';\nset ''state.savepoints.dir''=''file:///opt/data/flink_cluster/savepoints''; -- 目录自行修改\nset ''state.checkpoints.dir''= ''file:///opt/data/flink_cluster/checkpoints''; -- 目录自行修改\n-- set state.checkpoint-storage=''filesystem'';\nset ''state.backend.type''=''rocksdb'';\nset ''execution.checkpointing.interval''=''60 s'';\nset ''state.checkpoints.num-retained''=''100'';\n-- 使 solt 均匀分布在 各个 TM ', 'checkpoint config', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:55.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:55.0', NULL),
(17, 'note template', '10', '-- -----------------------------------------------------------------\n-- @Description(作业描述): ${1:}\n-- @Creator(创建人): ${2:}\n-- @Create DateTime(创建时间): ${3:}\n-- -----------------------------------------------------------------\n${4:}', 'note template', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:56.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:56.0', NULL),
(18, 'dinky_paimon_auto_create_table', '10', '-- -----------------------------------------------------------------\n-- 该 demo 用于创建 mysql-cdc 到 paimon 的整库同步案例 并使用自动建表,注意 #{schemaName} 和 #{tableName} 为固定写法,不要修改,用于动态获取库名和表名\n-- -----------------------------------------------------------------\nEXECUTE CDCSOURCE dinky_paimon_auto_create_table\nWITH\n  (\n    ''connector'' = ''mysql-cdc'',\n    ''hostname'' = '''',\n    ''port'' = '''',\n    ''username'' = '''',\n    ''password'' = '''',\n    ''checkpoint'' = ''10000'',\n    ''parallelism'' = ''1'',\n    ''scan.startup.mode'' = ''initial'',\n    ''database-name'' = ''dinky'',\n    ''sink.connector'' = ''paimon'',\n    ''sink.path'' = ''hdfs:/tmp/paimon/#{schemaName}.db/#{tableName}'',\n    ''sink.auto-create'' = ''true'',\n  );', 'dinky_paimon_auto_create_table', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:56.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:56.0', NULL),
(19, 'create.table.kafka', '11', 'CREATE TABLE Kafka_Table (\n  event_time TIMESTAMP(3) METADATA FROM ''timestamp'',\n  partition BIGINT METADATA VIRTUAL,\n  offset BIGINT METADATA VIRTUAL,\n  user_id BIGINT,\n  item_id BIGINT,\n  behavior STRING\n) WITH (\n  ''connector'' = ''kafka'',\n  ''topic'' = ''user_behavior'',\n  ''properties.bootstrap.servers'' = ''localhost:9092'',\n  ''properties.group.id'' = ''testGroup'',\n  ''scan.startup.mode'' = ''earliest-offset'',\n  ''format'' = ''csv''\n);\n--可选: ''value.fields-include'' = ''ALL'',\n--可选: ''json.ignore-parse-errors'' = ''true'',\n--可选: ''key.fields-prefix'' = ''k_'',', 'kafka快速建表格式', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:19:31.0', NULL, NULL, TIMESTAMP '2025-06-25 14:19:31.0', NULL),
