(25, 'create.stream.table.hive', '11', 'CREATE CATALOG hive WITH ( --创建hive的catalog\n    ''type'' = ''hive'',\n    ''hive-conf-dir'' = ''/app/wwwroot/MBDC/hive/conf/'',\n    ''hadoop-conf-dir''=''/app/wwwroot/MBDC/hadoop/etc/hadoop/''\n);\nUSE CATALOG hive;\nUSE offline_db; --选择库\nset table.sql-dialect=hive; --设置方言\nCREATE TABLE hive_stream_table (\n  user_id STRING,\n  order_amount DOUBLE\n) PARTITIONED BY (dt STRING, hr STRING) STORED AS parquet TBLPROPERTIES (\n  ''partition.time-extractor.timestamp-pattern''=''$dt $hr:00:00'',\n  ''sink.partition-commit.trigger''=''partition-time'',\n  ''sink.partition-commit.delay''=''1min'',\n  ''sink.semantic'' = ''exactly-once'',\n  ''sink.rolling-policy.rollover-interval'' =''1min'',\n  ''sink.rolling-policy.check-interval''=''1min'',\n  ''sink.partition-commit.policy.kind''=''metastore,success-file''\n);', '创建流式HIVE表', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL),
(26, 'create.table.mysql_cdc', '11', 'CREATE TABLE mysql_cdc_table(\n    cid INT,\n    sid INT,\n    cls STRING,\n    score INT,\n    PRIMARY KEY (cid) NOT ENFORCED\n) WITH (\n''connector'' = ''mysql-cdc'',\n''hostname'' = ''127.0.0.1'',\n''port'' = ''3306'',\n''username'' = ''test'',\n''password'' = ''123456'',\n''database-name'' = ''test'',\n''server-time-zone'' = ''UTC'',\n''scan.incremental.snapshot.enabled'' = ''true'',\n''debezium.snapshot.mode''=''latest-offset'' ,-- 或者key是scan.startup.mode，initial表示要历史数据，latest-offset表示不要历史数据\n''debezium.timestamp(6).format.date''=''yyyy-MM-dd'',\n''debezium.timestamp(6).format.time''=''HH-mm-ss'',\n''debezium.timestamp(6).format.timestamp(6)''=''yyyy-MM-dd HH-mm-ss'',\n''debezium.timestamp(6).format.timestamp''=''yyyy-MM-dd HH-mm-ss'',\n''debezium.timestamp(6).format.timestamp.zone''=''UTC+8'',\n''table-name'' = ''mysql_cdc_table'');', '创建Mysql_CDC表', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL),
(27, 'create.table.hudi', '11', 'CREATE TABLE hudi_table\n(\n    goods_order_id  bigint COMMENT ''自增主键id'',\n    goods_order_uid string COMMENT ''订单uid'',\n    customer_uid    string COMMENT ''客户uid'',\n    customer_name   string COMMENT ''客户name'',\n    create_time     timestamp(3) COMMENT ''创建时间'',\n    update_time     timestamp(3) COMMENT ''更新时间'',\n    create_by       string COMMENT ''创建人uid（唯一标识）'',\n    update_by       string COMMENT ''更新人uid（唯一标识）'',\n    PRIMARY KEY (goods_order_id) NOT ENFORCED\n) COMMENT ''hudi_table''\nWITH (\n''connector'' = ''hudi'',\n''path'' = ''hdfs://cluster1/data/bizdata/cdc/mysql/order/goods_order'', -- 路径会自动创建\n''hoodie.datasource.write.recordkey.field'' = ''goods_order_id'', -- 主键\n''write.precombine.field'' = ''update_time'', -- 相同的键值时，取此字段最大值，默认ts字段\n''read.streaming.skip_compaction'' = ''true'', -- 避免重复消费问题\n''write.bucket_assign.tasks'' = ''2'', -- 并发写的 bucekt 数\n''write.tasks'' = ''2'',\n''compaction.tasks'' = ''1'',\n''write.operation'' = ''upsert'', -- UPSERT（插入更新）\\INSERT（...', '创建hudi表', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL),
(28, 'CREATE TABLE Like', '11', 'DROP TABLE IF EXISTS sink_table;\nCREATE TABLE IF not EXISTS sink_table\nWITH (\n    ''topic'' = ''motor_vehicle_error''\n)\nLIKE source_table;', 'CREATE TABLE Like source table', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:18.0', NULL),
(29, 'CREATE TABLE like source_table EXCLUDING', '11', 'DROP TABLE IF EXISTS sink_table;\nCREATE TABLE IF not EXISTS sink_table(\n     -- Add watermark definition\n    WATERMARK FOR order_time AS order_time - INTERVAL ''5'' SECOND\n)\nWITH (\n    ''topic'' = ''motor_vehicle_error''\n)\nLIKE source_table (\n     -- Exclude everything besides the computed columns which we need to generate the watermark for.\n    -- We do not want to have the partitions or filesystem options as those do not apply to kafka.\n    EXCLUDING ALL\n    INCLUDING GENERATED\n);', 'CREATE TABLE like source_table EXCLUDING', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:54.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:54.0', NULL),
(30, 'CREATE TABLE ctas_kafka', '11', 'CREATE TABLE my_ctas_table\nWITH (\n    ''connector'' = ''kafka''\n)\nAS SELECT id, name, age FROM source_table WHERE mod(id, 10) = 0;', 'CREATE TABLE ctas_kafka', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:54.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:54.0', NULL),
(31, 'CREATE TABLE rtas_kafka', '11', 'CREATE OR REPLACE TABLE my_ctas_table\nWITH (\n    ''connector'' = ''kafka''\n)\nAS SELECT id, name, age FROM source_table WHERE mod(id, 10) = 0;', 'CREATE TABLE rtas_kafka', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:55.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:55.0', NULL),
(32, 'datagen job demo', '11', 'DROP TABLE IF EXISTS source_table3;\nCREATE TABLE IF NOT EXISTS source_table3(\n--订单id\norder_id BIGINT,\n--产品\nproduct BIGINT,\n--金额\namount BIGINT,\n--支付时间\norder_time as CAST(CURRENT_TIMESTAMP AS TIMESTAMP(3)), -- 在这里插入代码片\n--WATERMARK\nWATERMARK FOR order_time AS order_time - INTERVAL ''2'' SECOND\n) WITH(\n''connector'' = ''datagen'',\n ''rows-per-second'' = ''1'',\n ''fields.order_id.min'' = ''1'',\n ''fields.order_id.max'' = ''2'',\n ''fields.amount.min'' = ''1'',\n ''fields.amount.max'' = ''10'',\n ''fields.product.min'' = ''1'',\n ''fields.product.max'' = ''2''\n);\n-- SELECT * FROM source_table3 LIMIT 10;\nDROP TABLE IF EXISTS sink_table5;\nCREATE TABLE IF NOT EXISTS sink_table5(\n--产品\nproduct BIGINT,\n--金额\namount BIGINT,\n--支付时间\norder_time TIMESTAMP(3),\n--1分钟时间聚合总数\none_minute_sum BIGINT\n) WITH(\n''connector''=''print''\n);\nINSERT INTO sink_table5\nSELECT\nproduct,\namount,\norder_time,\nSUM(amount) OVER(\nPARTITION BY product\nORDER BY order_time\n-- 标识统计范围是1个 product...', 'datagen job demo', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:55.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:55.0', NULL),
(33, 'checkpoint config', '11', '-- 声明一些调优参数 (checkpoint 等相关配置)\nset ''execution.checkpointing.checkpoints-after-tasks-finish.enabled'' =''true'';\nSET ''pipeline.operator-chaining'' = ''false'';\nset ''state.savepoints.dir''=''file:///opt/data/flink_cluster/savepoints''; -- 目录自行修改\nset ''state.checkpoints.dir''= ''file:///opt/data/flink_cluster/checkpoints''; -- 目录自行修改\n-- set state.checkpoint-storage=''filesystem'';\nset ''state.backend.type''=''rocksdb'';\nset ''execution.checkpointing.interval''=''60 s'';\nset ''state.checkpoints.num-retained''=''100'';\n-- 使 solt 均匀分布在 各个 TM ', 'checkpoint config', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:55.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:55.0', NULL),
(34, 'note template', '11', '-- -----------------------------------------------------------------\n-- @Description(作业描述): ${1:}\n-- @Creator(创建人): ${2:}\n-- @Create DateTime(创建时间): ${3:}\n-- -----------------------------------------------------------------\n${4:}', 'note template', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:56.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:56.0', NULL),
(35, 'dinky_paimon_auto_create_table', '11', '-- -----------------------------------------------------------------\n-- 该 demo 用于创建 mysql-cdc 到 paimon 的整库同步案例 并使用自动建表,注意 #{schemaName} 和 #{tableName} 为固定写法,不要修改,用于动态获取库名和表名\n-- -----------------------------------------------------------------\nEXECUTE CDCSOURCE dinky_paimon_auto_create_table\nWITH\n  (\n    ''connector'' = ''mysql-cdc'',\n    ''hostname'' = '''',\n    ''port'' = '''',\n    ''username'' = '''',\n    ''password'' = '''',\n    ''checkpoint'' = ''10000'',\n    ''parallelism'' = ''1'',\n    ''scan.startup.mode'' = ''initial'',\n    ''database-name'' = ''dinky'',\n    ''sink.connector'' = ''paimon'',\n    ''sink.path'' = ''hdfs:/tmp/paimon/#{schemaName}.db/#{tableName}'',\n    ''sink.auto-create'' = ''true'',\n  );', 'dinky_paimon_auto_create_table', '1', '0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:56.0', NULL, NULL, TIMESTAMP '2025-06-25 14:20:56.0', NULL),
(36, 'create.table.dm8', '2', '-- 1. 建表\nCREATE TABLE t_user\n(\n    id          INT IDENTITY(1,1) PRIMARY KEY,                      -- 自增主键\n    username    VARCHAR(50) NOT NULL UNIQUE,                        -- 登录名，唯一\n    password    VARCHAR(64) NOT NULL,                               -- 密码密文\n    real_name   VARCHAR(50),                                        -- 真实姓名\n    email       VARCHAR(100) UNIQUE,                                -- 邮箱，唯一\n    phone       VARCHAR(20),                                        -- 手机号\n    status      CHAR(1)   DEFAULT ''1'' CHECK (status IN (''0'', ''1'')), -- 状态 1=启用 0=禁用\n    create_time TIMESTAMP DEFAULT SYSDATE,                          -- 创建时间\n    update_time TIMESTAMP DEFAULT SYSDATE                           -- 更新时间\n);\n-- 2. 插入示例数据\nINSERT INTO t_user (username, password, real_name, email, phone, status)\nVALUES (''zhangsan'', ''e10adc3949ba59abbe56e057f20f883e'', ''张三'', ''zhangsan@demo.com'', ''13800000001'', ''1''),\n       (''lisi'', ''25d55ad283aa400af464c76d713c...', 'Dm8快速建表', '1', '0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:15.0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:15.0', NULL),
(37, 'create.procedure.dm8', '2', '-- 创建（或替换）存储过程\nCREATE OR REPLACE PROCEDURE sp_get_user_info(\n    p_username   IN  VARCHAR2,      -- 输入参数：用户名\n    o_id         OUT INT,           -- 输出参数：用户ID\n    o_real_name  OUT VARCHAR2,      -- 输出参数：真实姓名\n    o_email      OUT VARCHAR2,      -- 输出参数：邮箱\n    o_phone      OUT VARCHAR2,      -- 输出参数：手机号\n    o_status     OUT CHAR,          -- 输出参数：状态\n    o_msg        OUT VARCHAR2       -- 输出参数：结果消息\n) AS\nBEGIN\n    -- 初始化输出\n    o_msg := ''SUCCESS'';\n    -- 查询\nSELECT id, real_name, email, phone, status\nINTO o_id, o_real_name, o_email, o_phone, o_status\nFROM t_user\nWHERE username = p_username\n  AND ROWNUM = 1;\n-- 若未找到，抛出异常\nIF o_id IS NULL THEN\n        RAISE_APPLICATION_ERROR(-20001, ''用户不存在'');\nEND IF;\nEXCEPTION\n    WHEN NO_DATA_FOUND THEN\n        o_msg := ''用户不存在'';\n        o_id := NULL;\nWHEN OTHERS THEN\n        o_msg := SQLERRM;\n        o_id := NULL;\nEND;', '创建Dm8存储过程', '1', '0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:15.0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:15.0', NULL),
(38, 'create.table.oracle', '3', '-- 1. 建表\nCREATE TABLE t_user\n(\n    id          NUMBER NOT NULL PRIMARY KEY,\n    username    VARCHAR2(50) NOT NULL UNIQUE,\n    password    VARCHAR2(64) NOT NULL,\n    real_name   VARCHAR2(50),\n    email       VARCHAR2(100) UNIQUE,\n    phone       VARCHAR2(20),\n    status      CHAR(1)   DEFAULT ''1'' CHECK (status IN (''0'', ''1'')),\n    create_time TIMESTAMP DEFAULT SYSTIMESTAMP,\n    update_time TIMESTAMP DEFAULT SYSTIMESTAMP\n);\n-- 2. 插入示例数据\nINSERT INTO t_user (id, username, password, real_name, email, phone, status)\nVALUES (''zhangsan'', ''e10adc3949ba59abbe56e057f20f883e'', ''张三'', ''zhangsan@demo.com'', ''13800000001'', ''1'');\nINSERT INTO t_user (id, username, password, real_name, email, phone, status)\nVALUES (1, ''lisi'', ''25d55ad283aa400af464c76d713c07ad'', ''李四'', ''lisi@demo.com'', ''13800000002'', ''1'');\nINSERT INTO t_user (id, username, password, real_name, email, phone, status)\nVALUES (1, ''wangwu'', ''5f4dcc3b5aa765d61d8327deb882cf99'', ''王五'', ''wangwu@d...', 'Oracle快速建表', '1', '0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:15.0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:15.0', NULL),
(39, 'create.procedure.oracle', '3', '--  存储过程：根据用户名返回用户完整信息\nCREATE OR REPLACE PROCEDURE sp_get_user_info(\n    p_username  IN  VARCHAR2,\n    o_id        OUT NUMBER,\n    o_real_name OUT VARCHAR2,\n    o_email     OUT VARCHAR2,\n    o_phone     OUT VARCHAR2,\n    o_status    OUT CHAR,\n    o_msg       OUT VARCHAR2\n) IS\nBEGIN\nSELECT id, real_name, email, phone, status\nINTO o_id, o_real_name, o_email, o_phone, o_status\nFROM t_user\nWHERE username = p_username\n  AND ROWNUM = 1;\no_msg := ''SUCCESS'';\nEXCEPTION\n    WHEN NO_DATA_FOUND THEN\n        o_msg := ''用户不存在'';\n        o_id := NULL;\nWHEN OTHERS THEN\n        o_msg := SQLERRM;\n        o_id := NULL;\nEND sp_get_user_info;', '创建Oracle存储过程', '1', '0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:15.0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:15.0', NULL),
(40, 'create.table.mysql', '4', '-- 1. 建表\nCREATE TABLE IF NOT EXISTS t_user (\n                                      id          INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n                                      username    VARCHAR(50)  NOT NULL UNIQUE,\n    password    VARCHAR(64)  NOT NULL,\n    real_name   VARCHAR(50),\n    email       VARCHAR(100) UNIQUE,\n    phone       VARCHAR(20),\n    status      CHAR(1)      DEFAULT ''1'' CHECK (status IN (''0'',''1'')),\n    create_time TIMESTAMP    DEFAULT CURRENT_TIMESTAMP,\n    update_time TIMESTAMP    DEFAULT CURRENT_TIMESTAMP \n    )\n;\n-- 2. 插入示例数据\nINSERT INTO t_user (username, password, real_name, email, phone, status) VALUES\n(''zhangsan'', ''e10adc3949ba59abbe56e057f20f883e'', ''张三'', ''zhangsan@demo.com'', ''13800000001'', ''1''),\n(''lisi'',     ''25d55ad283aa400af464c76d713c07ad'', ''李四'', ''lisi@demo.com'',     ''13800000002'', ''1''),\n(''wangwu'',   ''5f4dcc3b5aa765d61d8327deb882cf99'', ''王五'', ''wangwu@demo.com'',   ''13800000003'', ''0'');', 'Mysql快速建表', '1', '0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:16.0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:16.0', NULL),
(41, 'create.procedure.mysql', '4', '-- 存储过程：根据用户名返回用户信息\nDELIMITER $$\nCREATE OR REPLACE PROCEDURE sp_get_user_info(\n    IN  p_username  VARCHAR(50),\n    OUT o_id        INT,\n    OUT o_real_name VARCHAR(50),\n    OUT o_email     VARCHAR(100),\n    OUT o_phone     VARCHAR(20),\n    OUT o_status    CHAR(1),\n    OUT o_msg       VARCHAR(100)\n)\nBEGIN\n    DECLARE EXIT HANDLER FOR NOT FOUND\nBEGIN\n        SET o_msg = ''用户不存在'';\n        SET o_id = NULL;\nEND;\nSELECT id, real_name, email, phone, status\nINTO o_id, o_real_name, o_email, o_phone, o_status\nFROM t_user\nWHERE username = p_username\n    LIMIT 1;\nSET o_msg = ''SUCCESS'';\nEND$$\nDELIMITER ;', '创建Mysql存储过程', '1', '0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:16.0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:16.0', NULL),
(42, 'create.table.kingbase', '5', '-- 1. 建表\nCREATE TABLE t_user\n(\n    id          NUMBER NOT NULL PRIMARY KEY,\n    username    VARCHAR2(50) NOT NULL UNIQUE,\n    password    VARCHAR2(64) NOT NULL,\n    real_name   VARCHAR2(50),\n    email       VARCHAR2(100) UNIQUE,\n    phone       VARCHAR2(20),\n    status      CHAR(1)   DEFAULT ''1'' CHECK (status IN (''0'', ''1'')),\n    create_time TIMESTAMP DEFAULT SYSDATE,\n    update_time TIMESTAMP DEFAULT SYSDATE\n);\n-- 2. 插入示例数据\nINSERT INTO t_user (username, password, real_name, email, phone, status)\nVALUES (''zhangsan'', ''e10adc3949ba59abbe56e057f20f883e'', ''张三'', ''zhangsan@demo.com'', ''13800000001'', ''1''),\n       (''lisi'', ''25d55ad283aa400af464c76d713c07ad'', ''李四'', ''lisi@demo.com'', ''13800000002'', ''1''),\n       (''wangwu'', ''5f4dcc3b5aa765d61d8327deb882cf99'', ''王五'', ''wangwu@demo.com'', ''13800000003'', ''0'');\n', 'Kingbase快速建表', '1', '0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:16.0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:16.0', NULL),
(43, 'create.procedure.kingbase', '5', '--  存储过程：按用户名返回用户信息\nCREATE OR REPLACE PROCEDURE sp_get_user_info(\n    p_username  IN  VARCHAR2,\n    o_id        OUT NUMBER,\n    o_real_name OUT VARCHAR2,\n    o_email     OUT VARCHAR2,\n    o_phone     OUT VARCHAR2,\n    o_status    OUT CHAR,\n    o_msg       OUT VARCHAR2\n) AS\nBEGIN\nBEGIN\nSELECT id, real_name, email, phone, status\nINTO o_id, o_real_name, o_email, o_phone, o_status\nFROM t_user\nWHERE username = p_username AND ROWNUM = 1;\no_msg := ''SUCCESS'';\nEXCEPTION\n        WHEN NO_DATA_FOUND THEN\n            o_msg := ''用户不存在'';\n            o_id := NULL;\nWHEN OTHERS THEN\n            o_msg := SQLERRM;\n            o_id := NULL;\nEND;\nEND sp_get_user_info;', '创建Kingbase存储过程', '1', '0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:16.0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:16.0', NULL),
(44, 'create.table.hive', '8', '-- 1.建表\nCREATE TABLE IF NOT EXISTS t_user (\n    id          BIGINT,\n    username    STRING,\n    password    STRING,\n    real_name   STRING,\n    email       STRING,\n    phone       STRING,\n    status      CHAR(1),\n    create_time TIMESTAMP,\n    update_time TIMESTAMP\n) CLUSTERED BY (id) INTO 4 BUCKETS STORED AS ORC\nTBLPROPERTIES (''transactional''=''true'',''orc.compress''=''ZLIB'');\n-- 2. 插入示例数据\nINSERT INTO TABLE t_user VALUES\n(1, ''zhangsan'', ''e10adc3949ba59abbe56e057f20f883e'', ''张三'', ''zhangsan@demo.com'', ''13800000001'', ''1'', current_timestamp, current_timestamp),\n(2, ''lisi'',     ''25d55ad283aa400af464c76d713c07ad'', ''李四'', ''lisi@demo.com'',     ''13800000002'', ''1'', current_timestamp, current_timestamp),\n(3, ''wangwu'',   ''5f4dcc3b5aa765d61d8327deb882cf99'', ''王五'', ''wangwu@demo.com'',   ''13800000003'', ''0'', current_timestamp, current_timestamp);\n', 'Hive快速建表', '1', '0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:16.0', NULL, NULL, TIMESTAMP '2025-07-21 09:53:16.0', NULL),
(46, 'spark sql', '9', '-- 注册 MySQL 表为临时视图\nCREATE OR REPLACE TEMPORARY VIEW v_user\nUSING JDBC\nOPTIONS (\n  url \"jdbc:mysql://localhost:3306/demo?useSSL=false&serverTimezone=UTC\",\n  dbtable \"t_user\",\n  user \"账号\",\n  password \"密码\",\n  driver \"com.mysql.cj.jdbc.Driver\"\n);', 'spark sql', '1', '0', NULL, NULL, TIMESTAMP '2025-07-21 10:43:15.0', NULL, NULL, TIMESTAMP '2025-07-21 10:43:15.0', NULL);
