INSERT INTO public.system_notice (notice_id, notice_title, notice_type, notice_content, status, create_by, create_time, update_by, update_time, remark, top_flag, alert_flag, alert_start_time, alert_end_time, notice_content_text) VALUES
(1, 'qData 开源版重磅发布，赋能数据生态共建', '2', NULL, '0', '吴同', TIMESTAMP '2025-05-27 15:47:20.0', 'wutong', TIMESTAMP '2025-09-23 14:24:41.0', NULL, 0, 0, NULL, NULL, '<p class=\"ql-align-justify\"><strong style=\"color: rgb(60, 60, 67);\">江苏千桐科技有限</strong><span style=\"color: rgb(64, 72, 91);\">公司自主开源核心平台——数据中台“qData”，致力于构建开放、共享、可持续的技术生态，赋能开发者与合作伙伴，共同推动智能化技术创新。</span></p><p class=\"ql-align-justify\"><img src=\"https://wdcdn.qpic.cn/MTY4ODg1MDA2NTY0ODY1MA_811419__o3wPbAJJK_CpNhV_1758092306?w=1920&amp;h=300&amp;type=image/png\" height=\"94.4896\" width=\"604.733\"></p><p class=\"ql-align-justify\"><strong style=\"color: rgb(60, 60, 67);\">qData 数据中台</strong><span style=\"color: rgb(60, 60, 67);\">是一套集数据集成、标准管理、资产治理、质量控制、服务开放与智能分析于一体的企业级数据管理平台，致力于帮助企业实现数据资源的统一管理、高效治理与价值释放。我们秉承“</span><strong style=\"color: rgb(60, 60, 67);\">高效、安全、灵活、开放</strong><span style=\"color: rgb(60, 60, 67);\">”的理念，持续引入前沿技术，让数据真正成为企业发展的核心驱动力。</span></p><p class=\"ql-align-justify\"><span style=\"color: rgb(60, 60, 67);\">qData 数据中台提供 </span><strong style=\"color: rgb(60, 60, 67);\">商业版</strong><span style=\"color: rgb(60, 60, 67);\"> 与 </span><strong style=\"color: rgb(60, 60, ...'),
(2, 'qData  商业版 v1.1.7 功能增强与升级', '2', NULL, '0', '吴同', TIMESTAMP '2025-08-01 14:56:47.0', 'wutong', TIMESTAMP '2025-09-23 14:23:29.0', NULL, 0, 0, NULL, NULL, '<p>版本类型：功能更新 + 问题修复</p><h2>🆕 新功能</h2><h3>1、标准数据元</h3><ul><li>数据元类型字段支持绑定稽查/清洗规则，逻辑与质量任务、转化组件保持一致</li><li>配置质量任务或转化组时，自动带入已绑定规则，支持二次修改</li></ul><h3>2、图谱展示</h3><ul><li>以图谱形式展示表、库、任务间依赖关系，支持缩放、拖拽</li><li>资产详情页展示当前表的上下游血缘链路</li></ul><h3>3、资产详情页优化</h3><ul><li>顶部展示基本信息，其余字段统一归入【概览】Tab，完整呈现所有字段</li><li>已存在血缘的数据源，资产视图可直接查看上下游关系（预留扩展接口）</li></ul><h3>4、数据质量</h3><ul><li>资产详情页新增【数据质量】Tab，展示任务、评分、趋势图</li><li>无任务时支持新建稽查任务（自动带入标准规则），可修改调度周期与规则</li><li>质量评分展示在资产列表中</li></ul><h3>5、数据清洗</h3><ul><li>资产详情页新增【数据清洗】Tab，展示最新清洗报告</li><li>支持新建清洗任务（自动带入规则），支持双执行引擎，可调整调度与规则</li></ul><h3>6、ETL 转化组件</h3><ul><li>完成列拆分多行、剪切字符串、设常量、双流 Join 等核心组件开发</li><li>优化值映射、字段选择、字符串操作等已有组件逻辑</li><li>表输入组件仅展示“我申请到的资产”</li></ul><h3>7、转化组组件</h3><ul><li>交互逻辑重构，与质量任务规则添加方式保持一致</li><li>支持10类清洗规则实现，兼容主流数据库类型</li></ul><h2>🐛 问题修复</h2><h3>1、日志问题</h3><ul><li>解决 DS 与后端必须部署在一起的问题，支持多节点日志合并</li></ul><h3>2、数据源管理</h3><ul><li>优化无权限拉取表结构时的报错提示，隐藏代码细节</li></ul><h3>3、逻辑模型</h3><ul><li>修复物化失败无提示问题</li><li>主键字段自动设为必填且不可修改</li><li>修复人大金仓字段长度不一致问题</li>...'),
(3, '直播预告｜与qData团队开源面对面', '1', NULL, '0', '吴同', TIMESTAMP '2025-07-13 15:47:20.0', 'wutong', TIMESTAMP '2025-09-23 14:28:33.0', NULL, 0, 0, NULL, NULL, '<h1>📢 直播预告｜qData开源面对面：从0到1构建你的数据中台！</h1><p>qData团队首次与大家在线见面！一起见证 qData 的技术演进与社区成长！</p><p><strong>📌 精彩看点：</strong></p><p>1、qData 产品全景能力解析</p><p>2、一线工程师手把手 Demo 演示</p><p>3、社区路线图首次公开</p><p>4、用户互动，交流答疑</p><p><strong>📅 时间：</strong>2025年07月23日（周三）晚 20:00</p><p><strong> 1、地点：</strong>腾讯会议直播</p><p><strong> 2、立即报名：</strong>微信扫二维码预约观看直播！<img src=\"/prod-api//profile/2025/09/18/68cbad5be4b0649f2379b11d.png\"></p><p><br></p>'),
(4, 'qData 商业版 v1.1.8 稳定性提升更新', '2', NULL, '0', '吴同', TIMESTAMP '2025-09-10 14:56:47.0', 'wutong', TIMESTAMP '2025-09-23 14:27:50.0', NULL, 0, 0, NULL, NULL, '<p>版本类型：功能更新 + 问题修复</p><h2>🆕 新功能</h2><h3>1、清洗规则管理</h3><ul><li>新增规则分类管理（支持多级分类）  </li><li>录入规划中的全部规则（编码、名称、描述、场景、示例）  </li></ul><h3>2、数据资产</h3><ul><li>资产详情页优化</li><li>资产血缘集成：可直接查看数据源上下游关系  </li><li>新增质量 / 清洗 Tab，支持任务新增、报告展示、调度周期修改  </li></ul><h3>3、数据研发</h3><ul><li>新增/优化 ETL 转换组件</li><li>转化组组件交互逻辑重构，与质量任务规则交互保持一致  </li><li>表输入组件仅支持“我申请到的资产”  </li></ul><h3>4、数据服务</h3><ul><li>API 发布取消表范围限制，支持选择数据库内所有表  </li></ul><h2>🐛 问题修复</h2><p>1、日志问题：解决 DS 与后端必须部署在一起的问题，多节点日志合并  </p><p>2、数据源管理：拉取表结构无权限时，优化报错信息展示  </p><p>3、逻辑模型：物化失败无提示问题修复；字段主键必填逻辑优化；金仓字段类型长度不一致问题修复  </p>'),
(5, 'qData 商业版v1.1.9 新版本上线，功能全面优化', '2', NULL, '0', '吴同', TIMESTAMP '2025-09-23 00:47:20.0', 'wutong', TIMESTAMP '2025-09-23 14:27:18.0', NULL, 0, 0, NULL, NULL, '<p>版本类型：功能更新 + 问题修复</p><h2>🆕 新功能</h2><h3>1、稽查规则管理</h3><ul><li>按国标重建分类：完整性、唯一性、有效性、一致性、时效性</li><li>清除预置规则，按【稽查规则2.0】标准录入元数据</li><li>质量任务支持自动绑定稽查规则，可二次修改</li></ul><h3>2、清洗规则管理</h3><ul><li>新增两级分类体系，与【清洗规则2.0】对齐</li><li>完成全部清洗规则录入，支持数据元类型绑定</li></ul><h3>3、数据血缘（库表级）</h3><ul><li>自动解析 ETL 及 SQL 任务（Spark/Hive/Flink）的数据流动关系</li><li>支持列级血缘与多语句解析，资产详情页展示上下游链路</li><li>新增图谱化依赖视图，支持拖拽、缩放查看</li></ul><h3>4、资产清洗能力</h3><ul><li>资产详情页新增“数据清洗”Tab，展示最新清洗报告</li><li>支持一键创建清洗任务（自动带入标准规则），可修改调度周期</li></ul><h2>🐛 问题修复</h2><p><strong>1、部署架构</strong>：解决 DS 与 JAR 包必须部署在一起的问题，支持分布式部署</p><p><strong>2、日志系统</strong>：统一多节点日志采集与展示逻辑</p><p><strong>3、系统性能</strong>：修复应用授权缓存导致的响应慢问题</p><p><strong>4、数据标准</strong>：修复规则绑定异常、分类保存失败等问题</p><p><strong>5、数据资产</strong>：修复资产加载慢、质量报告缺失等问题</p><p><strong>6、数据研发</strong>：修复任务复制异常、SQL 解析中断等问题</p><p><strong>7、数据服务</strong>：修复 API 调用超时、参数映射错乱等问题</p>');
